const E=384,c=[.485,.456,.406],e=[.229,.224,.225];function M(s){const o=Math.max(...s),a=Array.from(s).map(t=>Math.exp(t-o)),n=a.reduce((t,r)=>t+r,0);return a.map(t=>t/n)}function m(s,o){const a=Math.min(s,o),n=Math.floor((s-a)/2),t=Math.floor((o-a)/2);return{sx:n,sy:t,sSize:a}}function p(s){const{data:o}=s,a=384*384,n=new Float32Array(3*a);for(let t=0;t<a;t++){const r=t*4;n[t]=(o[r]/255-c[0])/e[0],n[a+t]=(o[r+1]/255-c[1])/e[1],n[2*a+t]=(o[r+2]/255-c[2])/e[2]}return n}export{E as M,m as c,p,M as s};
